27	// Resolve produces a sealed ResolvedConfig by layering overrides onto
28	// cfg. Overrides are applied as last-write-wins per field. The
29	// returned ResolvedConfig does not alias cfg's storage — every map
30	// and slice is deep-cloned via per-type Clone methods before being
31	// captured.
32	//
33	// Resolve accepts a nil cfg and returns a ResolvedConfig populated
34	// from package defaults, sealed normally.
35	func (c *NewConfig) Resolve(overrides CLIOverrides) ResolvedConfig {
36		r := ResolvedConfig{sealed: true}
37	
38		r.assignee = overrides.Assignee
39		r.reviewMaxRetries = c.ResolveReviewMaxRetries()
40	
41		var agent *AgentConfig
42		if c != nil {
43			agent = c.Agent.Clone()
44		}
45	
46		r.harness = overrides.Harness
47		if r.harness == "" && agent != nil {
48			r.harness = agent.Harness
49		}
50	
51		r.model = overrides.Model
52		if r.model == "" && agent != nil {
53			r.model = agent.Model
54		}
55	
56		r.provider = overrides.Provider
57		r.modelRef = overrides.ModelRef
58		r.profile = overrides.Profile
59		r.minTier = overrides.MinTier
60		r.maxTier = overrides.MaxTier
61		r.effort = overrides.Effort
62	
63		r.permissions = overrides.Permissions
64		if r.permissions == "" && agent != nil {
65			r.permissions = agent.Permissions
66		}
67	
68		if overrides.Timeout != nil {
69			r.timeout = *overrides.Timeout
70		} else if agent != nil && agent.TimeoutMS > 0 {
71			r.timeout = time.Duration(agent.TimeoutMS) * time.Millisecond
72		}
73	
74		r.evidenceCaps = c.ResolveEvidenceCaps(r.harness)
75	
76		if agent != nil {
77			r.sessionLogDir = agent.SessionLogDir
78			if agent.ReasoningLevels != nil {
79				r.reasoningLevels = make(map[string][]string, len(agent.ReasoningLevels))
80				for k, v := range agent.ReasoningLevels {
81					r.reasoningLevels[k] = append([]string(nil), v...)
82				}
83			}
84			if agent.Routing != nil {
85				r.resolvedLadder = map[string][]string{
86					r.profile: agent.Routing.ResolvedLadder(r.profile),
87				}
88			}
89		}
90		if r.resolvedLadder == nil {
91			r.resolvedLadder = map[string][]string{
92				r.profile: (*RoutingConfig)(nil).ResolvedLadder(r.profile),
93			}
94		}
95	
96		if c != nil && c.Executions != nil && c.Executions.Mirror != nil {
97			r.mirrorConfig = c.Executions.Mirror.Clone()
98		}
99	
100		return r
101	}
