103	// ResolvedConfig is the loop/runner/reviewer's view of merged project
104	// config plus per-invocation overrides. It is constructed only by
105	// (*Config).Resolve / config.LoadAndResolve and is safe to share across
106	// goroutines (no method mutates it).
107	//
108	// Sealed-construction: every public accessor calls requireSealed on
109	// entry. A zero-value ResolvedConfig{} or `var r ResolvedConfig` is a
110	// valid Go expression but fails loudly on first read with a panic
111	// naming LoadAndResolve. See SD-024 / TD-024.
112	type ResolvedConfig struct {
113		sealed bool
114	
115		assignee                string
116		reviewMaxRetries        int
117		noProgressCooldown      time.Duration
118		maxNoChangesBeforeClose int
119		heartbeatInterval       time.Duration
120		harness                 string
121		model                   string
122		provider                string
123		modelRef                string
124		profile                 string
125		minTier                 string
126		maxTier                 string
127		effort                  string
128		permissions             string
129		timeout                 time.Duration
130		wallClock               time.Duration
131		contextBudget           string
132		evidenceCaps            evidence.Caps
133		sessionLogDir           string
134		mirrorConfig            *ExecutionsMirrorConfig
135		resolvedLadder          map[string][]string
136		reasoningLevels         map[string][]string
137	}
