139	// requireSealed panics if r was not produced by Resolve / LoadAndResolve.
140	// Called as the first statement of every public accessor.
141	func (r ResolvedConfig) requireSealed() {
142		if !r.sealed {
143			panic("config: ResolvedConfig used without going through " +
144				"(*Config).Resolve or config.LoadAndResolve. " +
145				"Production callers must obtain a ResolvedConfig from " +
146				"LoadAndResolve; tests must use NewTestConfigFor*.")
147		}
148	}
