43	// expectSealedPanic asserts that fn panics with a message naming
44	// LoadAndResolve.
45	func expectSealedPanic(t *testing.T, label string, fn func()) {
46		t.Helper()
47		defer func() {
48			r := recover()
49			if r == nil {
50				t.Fatalf("%s: expected panic, got none", label)
51			}
52			msg, ok := r.(string)
53			if !ok {
54				t.Fatalf("%s: panic value not a string: %T %v", label, r, r)
55			}
56			if !strings.Contains(msg, "LoadAndResolve") {
57				t.Fatalf("%s: panic message %q does not name LoadAndResolve", label, msg)
58			}
59		}()
60		fn()
61	}
